import * as THREE from 'three'

export class Vehicle {
  constructor() {
    this.group = new THREE.Group()

    const bodyMaterial = new THREE.MeshStandardMaterial({
      color: '#55ffff',
      emissive: '#00ffff',
      emissiveIntensity: 0.6,
      metalness: 0.4,
      roughness: 0.3,
    })

    const canopyMaterial = new THREE.MeshStandardMaterial({
      color: '#ff77ff',
      emissive: '#ff00ff',
      emissiveIntensity: 0.5,
      metalness: 0.5,
      roughness: 0.25,
    })

    const wheelMaterial = new THREE.MeshStandardMaterial({
      color: '#222233',
      emissive: '#00ffff',
      emissiveIntensity: 0.25,
      metalness: 0.2,
      roughness: 0.8,
    })

    const body = new THREE.Mesh(new THREE.BoxGeometry(1.8, 0.5, 3.2), bodyMaterial)
    body.position.y = 0.6
    this.group.add(body)

    const canopy = new THREE.Mesh(new THREE.BoxGeometry(1.0, 0.35, 1.2), canopyMaterial)
    canopy.position.set(0, 0.95, 0.1)
    this.group.add(canopy)

    const wheelGeometry = new THREE.BoxGeometry(0.35, 0.35, 0.65)
    const wheelOffsets = [
      [-0.95, 0.25, 1.05],
      [0.95, 0.25, 1.05],
      [-0.95, 0.25, -1.05],
      [0.95, 0.25, -1.05],
    ]

    wheelOffsets.forEach(([x, y, z]) => {
      const wheel = new THREE.Mesh(wheelGeometry, wheelMaterial)
      wheel.position.set(x, y, z)
      this.group.add(wheel)
    })

    const thrusterMaterial = new THREE.MeshStandardMaterial({
      color: '#ff66ff',
      emissive: '#ff00ff',
      emissiveIntensity: 0.8,
      metalness: 0.3,
      roughness: 0.4,
    })

    const thrusterGeometry = new THREE.BoxGeometry(0.35, 0.2, 0.45)
    const thrusterL = new THREE.Mesh(thrusterGeometry, thrusterMaterial)
    thrusterL.position.set(-0.45, 0.45, -1.9)
    this.group.add(thrusterL)

    const thrusterR = new THREE.Mesh(thrusterGeometry, thrusterMaterial)
    thrusterR.position.set(0.45, 0.45, -1.9)
    this.group.add(thrusterR)

    this.group.position.set(0, 0.15, 0)
    this.hoverTime = 0
  }

  update(delta) {
    this.hoverTime += delta
    this.group.position.y = 0.15 + Math.sin(this.hoverTime * 4) * 0.03
  }
}

import * as THREE from 'three'

export class CollectiblesManager {
  constructor(scene, count = 18) {
    this.scene = scene
    this.count = count
    this.items = []
    this.effects = []
    this.spawnTimer = 0
    this.spawnInterval = 2.5

    this.geom = new THREE.SphereGeometry(0.35, 16, 16)
    this.mat = new THREE.MeshStandardMaterial({
      color: '#aaffff',
      emissive: '#00ffff',
      emissiveIntensity: 1.2,
      metalness: 0.2,
      roughness: 0.15,
    })

    for (let i = 0; i < this.count; i++) this.spawnOrb()
  }

  randomPos() {
    return new THREE.Vector3(
      THREE.MathUtils.randFloatSpread(170),
      0.55,
      THREE.MathUtils.randFloatSpread(170),
    )
  }

  spawnOrb() {
    const orb = new THREE.Mesh(this.geom, this.mat.clone())
    orb.position.copy(this.randomPos())
    orb.userData.t = Math.random() * Math.PI * 2
    this.scene.add(orb)
    this.items.push(orb)
  }

  update(delta, vehiclePosition) {
    let collected = 0

    for (let i = this.items.length - 1; i >= 0; i--) {
      const orb = this.items[i]
      orb.userData.t += delta * 3
      orb.position.y = 0.55 + Math.sin(orb.userData.t) * 0.08

      const dist = orb.position.distanceTo(vehiclePosition)
      if (dist < 1.5) {
        collected += 1
        this.createCollectEffect(orb.position)
        this.scene.remove(orb)
        this.items.splice(i, 1)
      }
    }

    for (let i = this.effects.length - 1; i >= 0; i--) {
      const fx = this.effects[i]
      fx.life -= delta
      fx.mesh.scale.addScalar(delta * 2.5)
      fx.mesh.material.opacity = Math.max(0, fx.life / fx.maxLife)
      if (fx.life <= 0) {
        this.scene.remove(fx.mesh)
        this.effects.splice(i, 1)
      }
    }

    this.spawnTimer += delta
    if (this.items.length < this.count && this.spawnTimer >= this.spawnInterval) {
      this.spawnTimer = 0
      this.spawnOrb()
    }

    return collected
  }

  createCollectEffect(position) {
    const ring = new THREE.Mesh(
      new THREE.SphereGeometry(0.25, 12, 12),
      new THREE.MeshBasicMaterial({ color: '#ccffff', transparent: true, opacity: 0.8 }),
    )
    ring.position.copy(position)
    this.scene.add(ring)
    this.effects.push({ mesh: ring, life: 0.3, maxLife: 0.3 })
  }
}

import * as THREE from 'three'

export class ObstaclesManager {
  constructor(scene, count = 12) {
    this.scene = scene
    this.count = count
    this.obstacles = []
    this.hitCooldown = 0

    const material = new THREE.MeshStandardMaterial({
      color: '#440000',
      emissive: '#ff2233',
      emissiveIntensity: 0.9,
      metalness: 0.25,
      roughness: 0.65,
    })

    for (let i = 0; i < count; i++) {
      const h = THREE.MathUtils.randFloat(1.8, 4.8)
      const geo = new THREE.BoxGeometry(
        THREE.MathUtils.randFloat(1.2, 2.5),
        h,
        THREE.MathUtils.randFloat(1.2, 2.5),
      )
      const mesh = new THREE.Mesh(geo, material)
      mesh.position.set(
        THREE.MathUtils.randFloatSpread(170),
        h / 2,
        THREE.MathUtils.randFloatSpread(170),
      )
      this.scene.add(mesh)
      this.obstacles.push(mesh)
    }
  }

  update(delta, vehiclePosition) {
    if (this.hitCooldown > 0) this.hitCooldown -= delta

    let damage = 0
    for (const obstacle of this.obstacles) {
      const dx = obstacle.position.x - vehiclePosition.x
      const dz = obstacle.position.z - vehiclePosition.z
      const dist = Math.sqrt(dx * dx + dz * dz)
      if (dist < 1.8 && this.hitCooldown <= 0) {
        damage = 10
        this.hitCooldown = 0.45
        break
      }
    }

    return damage
  }
}

export class GameState {
  constructor() {
    this.score = 0
    this.health = 100
    this.gameOver = false
  }

  addScore(amount) {
    if (this.gameOver) return
    this.score += amount
  }

  applyDamage(amount) {
    if (this.gameOver) return
    this.health = Math.max(0, this.health - amount)
    if (this.health <= 0) this.gameOver = true
  }
}

