@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;600;800&display=swap');

:root {
  --neon-cyan: #00f5ff;
  --neon-magenta: #ff2bd6;
  --neon-blue: #59a6ff;
  --glass-bg: rgba(15, 22, 45, 0.45);
  --glass-border: rgba(130, 185, 255, 0.35);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  width: 100%;
  height: 100%;
  overflow: hidden;
  font-family: 'Orbitron', sans-serif;
  background: radial-gradient(circle at 20% 20%, #121d3d 0%, #070914 45%, #04050b 100%);
}

#game {
  display: block;
  width: 100vw;
  height: 100vh;
}

.hud-root {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 10;
}

.hud-panel {
  position: absolute;
  padding: 12px 16px;
  border: 1px solid var(--glass-border);
  border-radius: 14px;
  background: var(--glass-bg);
  backdrop-filter: blur(10px);
  box-shadow: inset 0 0 18px rgba(84, 150, 255, 0.2), 0 0 20px rgba(0, 245, 255, 0.18);
}

.hud-score {
  top: 16px;
  left: 16px;
  color: #dffeff;
  font-weight: 800;
  font-size: clamp(1.2rem, 2.2vw, 2.2rem);
  letter-spacing: 0.08em;
  text-shadow: 0 0 6px var(--neon-cyan), 0 0 18px var(--neon-cyan), 0 0 28px rgba(0, 245, 255, 0.45);
}

.hud-right {
  top: 16px;
  right: 16px;
  min-width: min(38vw, 320px);
  color: #eef5ff;
  font-size: 0.9rem;
}

.hud-label {
  opacity: 0.88;
  margin-bottom: 6px;
  font-size: 0.75rem;
  letter-spacing: 0.08em;
}

.hud-bar {
  width: 100%;
  height: 14px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.08);
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.15);
  margin-bottom: 10px;
}

.hud-fill {
  height: 100%;
  width: 100%;
  transition: width 120ms linear;
}

.hud-health {
  background: linear-gradient(90deg, #ff2d55 0%, #ffb703 45%, #37ff8b 100%);
  box-shadow: 0 0 8px rgba(55, 255, 139, 0.55);
}

.hud-boost {
  background: linear-gradient(90deg, #5f6bff 0%, #00f5ff 100%);
  box-shadow: 0 0 8px rgba(0, 245, 255, 0.55);
}

.menu-screen {
  position: fixed;
  inset: 0;
  z-index: 20;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  color: #eefaff;
  background: radial-gradient(circle at 50% 40%, rgba(34, 44, 90, 0.4), rgba(4, 5, 11, 0.95));
  padding: 24px;
}

.menu-hidden {
  display: none;
}

.menu-title {
  margin: 0;
  font-size: clamp(2rem, 8vw, 5.4rem);
  letter-spacing: 0.16em;
  color: #dff;
  text-shadow: 0 0 8px var(--neon-cyan), 0 0 18px var(--neon-cyan), 0 0 34px var(--neon-magenta);
  animation: pulseGlow 2s infinite alternate;
}

.menu-subtitle {
  margin-top: 18px;
  font-size: clamp(1rem, 2.5vw, 1.5rem);
  color: #b9cfff;
  text-shadow: 0 0 10px rgba(89, 166, 255, 0.8);
}

.menu-instructions {
  margin-top: 16px;
  max-width: 640px;
  line-height: 1.7;
  color: #d0dcff;
  opacity: 0.95;
}

.menu-score {
  margin-top: 12px;
  color: #ffffff;
  text-shadow: 0 0 10px #fff, 0 0 20px var(--neon-cyan);
}

@keyframes pulseGlow {
  from {
    text-shadow: 0 0 8px var(--neon-cyan), 0 0 16px var(--neon-cyan), 0 0 26px var(--neon-magenta);
  }
  to {
    text-shadow: 0 0 12px var(--neon-cyan), 0 0 24px var(--neon-cyan), 0 0 38px var(--neon-magenta);
  }
}

@media (max-width: 640px) {
  .hud-right {
    min-width: 52vw;
  }
}

export class MenuUI {
  constructor() {
    this.startScreen = this.createStartScreen()
    this.gameOverScreen = this.createGameOverScreen()
    document.body.append(this.startScreen, this.gameOverScreen)
  }

  createStartScreen() {
    const container = document.createElement('div')
    container.className = 'menu-screen'
    container.innerHTML = `
      <h1 class="menu-title">NEON DRIFT</h1>
      <p class="menu-subtitle">Press ENTER to Start</p>
      <p class="menu-instructions">WASD to move • Collect orbs to increase score • Avoid obstacles to survive.</p>
    `
    return container
  }

  createGameOverScreen() {
    const container = document.createElement('div')
    container.className = 'menu-screen menu-hidden'
    container.innerHTML = `
      <h1 class="menu-title">GAME OVER</h1>
      <p class="menu-score">Final Score: <span data-final-score>0</span></p>
      <p class="menu-subtitle">Press ENTER to Restart</p>
    `
    return container
  }

  showStart() {
    this.startScreen.classList.remove('menu-hidden')
    this.gameOverScreen.classList.add('menu-hidden')
  }

  showGameOver(score) {
    this.startScreen.classList.add('menu-hidden')
    this.gameOverScreen.classList.remove('menu-hidden')
    this.gameOverScreen.querySelector('[data-final-score]').textContent = String(score)
  }

  hideAll() {
    this.startScreen.classList.add('menu-hidden')
    this.gameOverScreen.classList.add('menu-hidden')
  }
}

export class GameState {
  constructor() {
    this.score = 0
    this.health = 100
    this.gameOver = false
    this.started = false
  }

  start() {
    this.started = true
    this.gameOver = false
  }

  reset() {
    this.score = 0
    this.health = 100
    this.gameOver = false
    this.started = true
  }

  addScore(amount) {
    if (this.gameOver || !this.started) return
    this.score += amount
  }

  applyDamage(amount) {
    if (this.gameOver || !this.started) return
    this.health = Math.max(0, this.health - amount)
    if (this.health <= 0) this.gameOver = true
  }
}

// Neon Drift — main entry point
import * as THREE from 'three'
import { Vehicle } from './vehicle'
import { VehicleController } from './controls'
import { CollectiblesManager } from './collectibles'
import { ObstaclesManager } from './obstacles'
import { GameState } from './game'
import { HUD } from './hud'
import { MenuUI } from './menu'
import './style.css'

const canvas = document.getElementById('game')

const renderer = new THREE.WebGLRenderer({
  canvas,
  antialias: true,
})
renderer.setSize(window.innerWidth, window.innerHeight)
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2))
renderer.setClearColor('#0a0a1a')

const scene = new THREE.Scene()
scene.background = new THREE.Color('#0a0a1a')
scene.fog = new THREE.Fog('#1a1230', 20, 180)

const camera = new THREE.PerspectiveCamera(
  75,
  window.innerWidth / window.innerHeight,
  0.1,
  1000,
)
camera.position.set(0, 5, 10)
camera.lookAt(0, 0, 0)

const ambientLight = new THREE.AmbientLight('#4b6cb7', 0.35)
scene.add(ambientLight)

const directionalLight = new THREE.DirectionalLight('#ffffff', 0.8)
directionalLight.position.set(0, 12, 6)
scene.add(directionalLight)

const cyanLight = new THREE.PointLight('#00ffff', 1.2, 100, 2)
cyanLight.position.set(-20, 6, -10)
scene.add(cyanLight)

const magentaLight = new THREE.PointLight('#ff00ff', 1.2, 100, 2)
magentaLight.position.set(20, 6, 10)
scene.add(magentaLight)

const groundGeometry = new THREE.PlaneGeometry(200, 200, 40, 40)
const groundMaterial = new THREE.MeshStandardMaterial({
  color: '#111122',
  emissive: '#1a3355',
  emissiveIntensity: 0.2,
  wireframe: true,
  roughness: 0.8,
  metalness: 0.1,
})
const ground = new THREE.Mesh(groundGeometry, groundMaterial)
ground.rotation.x = -Math.PI / 2
ground.position.y = 0
scene.add(ground)

const skyGeometry = new THREE.SphereGeometry(500, 32, 32)
const skyMaterial = new THREE.ShaderMaterial({
  side: THREE.BackSide,
  uniforms: {
    topColor: { value: new THREE.Color('#1b1442') },
    bottomColor: { value: new THREE.Color('#05050f') },
    offset: { value: 20.0 },
    exponent: { value: 0.8 },
  },
  vertexShader: `
    varying vec3 vWorldPosition;
    void main() {
      vec4 worldPosition = modelMatrix * vec4(position, 1.0);
      vWorldPosition = worldPosition.xyz;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    uniform vec3 topColor;
    uniform vec3 bottomColor;
    uniform float offset;
    uniform float exponent;
    varying vec3 vWorldPosition;
    void main() {
      float h = normalize(vWorldPosition + offset).y;
      float t = max(pow(max(h, 0.0), exponent), 0.0);
      gl_FragColor = vec4(mix(bottomColor, topColor, t), 1.0);
    }
  `,
})
const sky = new THREE.Mesh(skyGeometry, skyMaterial)
scene.add(sky)

let vehicle = new Vehicle()
scene.add(vehicle.group)

let controller = new VehicleController(vehicle, camera)
let collectibles = new CollectiblesManager(scene, 18)
let obstacles = new ObstaclesManager(scene, 12)
const gameState = new GameState()
const hud = new HUD()
const menu = new MenuUI()

function resetRun() {
  scene.remove(vehicle.group)
  collectibles.dispose?.()
  obstacles.dispose?.()

  vehicle = new Vehicle()
  scene.add(vehicle.group)

  controller = new VehicleController(vehicle, camera)
  collectibles = new CollectiblesManager(scene, 18)
  obstacles = new ObstaclesManager(scene, 12)
  gameState.reset()
  menu.hideAll()
  hud.setVisible(true)
}

function startRunIfNeeded() {
  if (!gameState.started || gameState.gameOver) {
    resetRun()
  }
}

window.addEventListener('keydown', (event) => {
  if (event.code !== 'Enter') return

  if (!gameState.started) {
    gameState.start()
    menu.hideAll()
    hud.setVisible(true)
  } else if (gameState.gameOver) {
    startRunIfNeeded()
  }
})

hud.setVisible(false)
menu.showStart()

function onWindowResize() {
  camera.aspect = window.innerWidth / window.innerHeight
  camera.updateProjectionMatrix()
  renderer.setSize(window.innerWidth, window.innerHeight)
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2))
}

window.addEventListener('resize', onWindowResize)

const clock = new THREE.Clock()

function animate() {
  requestAnimationFrame(animate)

  const delta = Math.min(clock.getDelta(), 0.05)

  if (gameState.started && !gameState.gameOver) {
    vehicle.update(delta)
    controller.update(delta)

    const collected = collectibles.update(delta, vehicle.group.position)
    if (collected > 0) gameState.addScore(collected)

    const damage = obstacles.update(delta, vehicle.group.position)
    if (damage > 0) gameState.applyDamage(damage)

    const speed = vehicle.velocity ? vehicle.velocity.length() : 0
    hud.update({
      score: gameState.score,
      health: gameState.health,
      speedNormalized: Math.min(speed / 30, 1),
    })
  }

  if (gameState.gameOver) {
    hud.setVisible(false)
    menu.showGameOver(gameState.score)
  }

  renderer.render(scene, camera)
}

